SELECT count(*) FROM movie_keyword, title, kind_type, cast_info, keyword, role_type, char_name, movie_info, movie_companies WHERE movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND movie_info.movie_id = title.id AND movie_companies.movie_id = title.id;